={{ (function() {
    const raw = $('Prepare Company Data').item.json.companyName || '';
    const isDomain = /^[a-zA-Z0-9][a-zA-Z0-9-]*(\.[a-zA-Z0-9-]+)*\.[a-zA-Z]{2,}$/.test(raw.trim());
    const cleaned = isDomain
      ? raw.trim().replace(/\.[^.]+$/, '').replace(/[-_.]/g, ' ')
      : raw;
    return 'https://r.jina.ai/https://duckduckgo.com/html/?q=' + encodeURIComponent(cleaned + ' company');
  })()}}

