const response = $json;
const geminiText = response?.candidates?.[0]?.content?.parts?.[0]?.text || '';
let category = geminiText.trim();

// Map display label to HubSpot internal enum value
if (category === 'Others') category = 'Unknown';

const prepData = $('Prepare Gemini Input - Search').item.json;

return {
  companyId: prepData.companyId,
  companyName: prepData.companyName,
  enrichmentSource: prepData.enrichmentSource,
  category: category,
  needsManualReview: false
};

const r = $('Preserve Pre-Update Data').item.json;
return {
  json: {
    companyId: r.companyId,
    companyName: r.companyName,
    enrichmentSource: r.enrichmentSource,
    category: r.category,
    needsManualReview: false
  }
};

const items = $json.data || [];

if (items.length === 0) {
  return { json: { message: '📊 No companies processed today.' } };
}

const categorized = items.filter(i => !i.needsManualReview);
const manualReview = items.filter(i => i.needsManualReview);

const today = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
let message = `*📊 Industry Categorization — ${today}*\n*${items.length} companies processed*\n`;

if (categorized.length > 0) {
  message += `\n✅ *${categorized.length} categorized:*\n`;
  for (const c of categorized) {
    const cat = c.category === 'Unknown' ? 'Others' : c.category;
    message += `• *${c.companyName}* → ${cat} _(${c.enrichmentSource})_ — <https://app.hubspot.com/contacts/142047914/company/${c.companyId}|View>\n`;
  }
}

if (manualReview.length > 0) {
  message += `\n⚠️ *${manualReview.length} need manual review:*\n`;
  for (const c of manualReview) {
    message += `• <https://app.hubspot.com/contacts/142047914/company/${c.companyId}|${c.companyName}>\n`;
  }
}

return { json: { message } };
